# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
import uuid

class Item:
    def __init__(self, name, quantity):
        self.id = str(uuid.uuid4())
        self.name = name
        self.quantity = quantity

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = {}

async def handle_connection(websocket, path):
    while True:
        try:
            data = await websocket.recv()
            message = json.loads(data)
            if message['action'] == 'get_inventory':
                await send_inventory(websocket, message['player_id'])
            elif message['action'] == 'trade_items':
                trade_data = message['trade_data']
                sender_player_id = trade_data['sender_player_id']
                receiver_player_id = trade_data['receiver_player_id']
                item_id = trade_data['item_id']
                quantity = trade_data['quantity']
                await handle_trade(sender_player_id, receiver_player_id, item_id, quantity)
            elif message['action'] == 'update_inventory':
                update_data = message['update_data']
                player_id = update_data['player_id']
                item_id = update_data['item_id']
                quantity = update_data['quantity']
                await update_item_owner(player_id, item_id, quantity)
        except websockets.ConnectionClosed:
            print(f"Connection closed for {message['player_id']}")
            break

async def send_inventory(websocket, player_id):
    inventory = Player.inventory[player_id]
    data = {'action': 'send_inventory', 'inventory': inventory}
    await websocket.send(json.dumps(data))

async def handle_trade(sender_player_id, receiver_player_id, item_id, quantity):
    sender_inventory = Player.inventory[sender_player_id].get(item_id, 0)
    if sender_inventory >= quantity:
        sender_inventory -= quantity
        receiver_inventory = Player.inventory[receiver_player_id].get(item_id, 0) + quantity
        await update_item_owner(sender_player_id, item_id, sender_inventory)
        await update_item_owner(receiver_player_id, item_id, receiver_inventory)

async def update_item_owner(player_id, item_id, quantity):
    if player_id in Player.inventory:
        Player.inventory[player_id][item_id] = quantity

async def start_server():
    app = websockets.serve(handle_connection, "localhost", 8765)
    await app.wait_closed()

class GameServer:
    async def main(self):
        asyncio.get_event_loop().run_until_complete(start_server())
        print("Game server started on port 8765")

if __name__ == "__main__":
    game_server = GameServer()
    asyncio.get_event_loop().run_until_complete(game_server.main())